import "./App.css";
import "./nav.css";
import Slider from "./Slider";
import Nav from "./nav";
import Tooler from "./tooler";
import MyProjects from "./myProjects";
import Footer from "./Footer";

import Programmer1 from "srcimagesprogrammer1.png";

function App() {
  return (
    <div className="App">
      <div className="header">
        <Nav />
        <h3 className="Radicc">RADICC</h3>
      </div>
      <div className="body">
        <div>
          <div className="divTomRadHi">
            <h2 className="tomRadHi">✌ Hi There! I'm Radicc</h2>
          </div>
          <h1 className="tomRadText">A Frontend developer</h1>
          <h3 className="tomRadUnderText">
            I am a selfthouhgt frontend developer trying to change profession.
          </h3>
        </div>
        <div>
          <img src={Programmer1} />
        </div>
        <Slider />
      </div>
      <Tooler />
      <MyProjects />
      <Footer />
    </div>
  );
}
export default App;
